import * as React from 'react';
import type { PopperProps } from '..';
import { Popper } from '..';

const timeout = { appear: 1, enter: 1, exit: 1 };

const RecursivePopover = ({
  prefix = 'root',
  size = 2,
  ...restProps
}: {
  prefix?: string;
  size?: number;
} & Omit<PopperProps, 'children' | 'popup'>) => (
  <>
    {Array(size)
      .fill(0)
      .map((_, i) => (
        <Popper
          timeout={timeout}
          popupClassName={`${prefix}-${i}-popup`}
          key={i}
          popup={
            <div
              id={`${prefix}-${i}-popup`}
              style={{
                padding: 16,
                background: 'white',
                border: '1px solid black',
              }}
            >
              <RecursivePopover prefix={`${prefix}-${i}`} {...restProps} />
            </div>
          }
          {...restProps}
        >
          <button id={`${prefix}-${i}-button`} type="button">
            {`${prefix}-${i}`}
          </button>
        </Popper>
      ))}
  </>
);

export default RecursivePopover;
